    '\n  *[_type == "product" && store.slug.current == $slug][0] {\n    _id,\n    _type,\n    relatedArticles[]-> {\n      \n  _id,\n  "title": coalesce(\n    title[_key == $language][0].value,\n    title[0].value\n  ),\n  "slug": slug.current,\n  publishedAt,\n  category-> {\n    "title": coalesce(\n      title[_key == $language][0].value,\n      title[0].value\n    ),\n    "slug": slug.current\n  },\n  image {\n    \n  ...,\n  asset-> {\n    _id,\n    altText\n  }\n\n  }\n\n    }\n  }\n': ProductRelatedArticlesQueryResult;
    '\n  *[_type == "home" || _type == "page"] {\n    _updatedAt,\n    "path": select(\n      _type == "home" => "/",\n      _type == "page" => "/pages/" + slug.current\n    )\n  }\n': SitemapQueryResult;
